{
  "terms": [
    {
      "term": "Transposition",
      "simpleDefinition": "Rearranging a mathematical formula to solve for a specific unknown variable.",
      "anchor": "Changing the subject of a formula like V=IR to find Resistance (R=V/I).",
      "misconception": "Believing you can move a term across the equals sign without performing the inverse operation."
    },
    {
      "term": "Indices",
      "simpleDefinition": "Small numbers (powers) that indicate how many times a base number is multiplied by itself.",
      "anchor": "Using powers of 10 to represent kilo (10^3) or milli (10^-3) in electrical units.",
      "misconception": "Thinking that 10 to the power of 3 (10^3) equals 30 instead of 1,000."
    },
    {
      "term": "Trigonometry",
      "simpleDefinition": "The branch of mathematics dealing with the relationships between the sides and angles of triangles.",
      "anchor": "Using SOH CAH TOA to calculate values in an impedance or power triangle.",
      "misconception": "Incorrectly identifying the 'Opposite' and 'Adjacent' sides by ignoring the position of the reference angle."
    },
    {
      "term": "Pythagoras’ Theorem",
      "simpleDefinition": "A formula (a² + b² = c²) used to find the length of a missing side in a right-angled triangle.",
      "anchor": "Calculating total impedance (Z) when resistance and reactance are known.",
      "misconception": "Forgetting to square the individual values before adding them together."
    },
    {
      "term": "Mean",
      "simpleDefinition": "The average value calculated by adding a set of numbers and dividing by the total count.",
      "anchor": "Finding the average reading from a series of earth loop impedance tests.",
      "misconception": "Confusing the 'Mean' (average) with the 'Mode' (the most frequent value in a set)."
    },
    {
      "term": "Derating Factor",
      "simpleDefinition": "A percentage or decimal used to reduce the maximum current rating of a cable due to environmental conditions.",
      "anchor": "Multiplying a cable's capacity by 0.8 to account for grouping or high temperatures.",
      "misconception": "Applying a percentage as a whole number instead of converting it to a decimal multiplier."
    }
  ],
  "anchorPhrases": [
    "Change the subject of the formula",
    "Apply the inverse operation",
    "Powers of 10 notation",
    "Right-angled triangle calculation",
    "Statistical average of test results"
  ],
  "misconceptionTargets": [
    "Indices are not simple multiplication; they are repeated multiplication.",
    "The hypotenuse is always the longest side, opposite the right angle.",
    "Transposition requires doing the same thing to both sides of the equals sign.",
    "A percentage must be converted to a decimal before multiplying in a formula."
  ]
}

{
  "teachChecks": [
    {
      "title": "Fractions, Percentages, and Indices",
      "basicQuestions": [
        {
          "questionText": "How do you convert a percentage into a decimal for use in an electrical calculation?",
          "answerGuidance": [
            "Divide by 100",
            "Divide the percentage by 100"
          ],
          "hint": "Think about what the word 'percent' (per hundred) literally means.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is the numerical value of the index 10 to the power of 3 (10³)?",
          "answerGuidance": [
            "1,000",
            "One thousand",
            "1000"
          ],
          "hint": "This is 10 multiplied by itself three times.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Which electrical prefix is represented by the index 10 to the power of -3 (10⁻³)?",
          "answerGuidance": [
            "Milli",
            "m"
          ],
          "hint": "This prefix makes a unit 1,000 times smaller.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why is it necessary to convert a 70% derating factor into the decimal 0.7 before applying it to a cable's current-carrying capacity?",
      "deeperAnswerGuidance": [
        "Percentages represent a portion of 100",
        "Mathematical formulas require decimal multipliers",
        "Multiplying by 70 would incorrectly increase the value",
        "Decimals allow for direct multiplication in calculations"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2"
      ],
      "hint": "Consider what would happen to the cable's rating if you multiplied it by the whole number 70 instead of a decimal."
    },
    {
      "title": "Algebra and Transposition",
      "basicQuestions": [
        {
          "questionText": "What is the term for the single variable placed alone before the equals sign in a formula?",
          "answerGuidance": [
            "Subject",
            "The subject"
          ],
          "hint": "This is the unknown value you are trying to solve for.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is the inverse operation of multiplication when transposing a formula?",
          "answerGuidance": [
            "Division",
            "Divide"
          ],
          "hint": "To move a multiplied term across the equals sign, you must do the opposite.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What is the transposed version of the formula V = I × R when solving for Resistance (R)?",
          "answerGuidance": [
            "R = V / I",
            "R = V divided by I"
          ],
          "hint": "You need to move the Current (I) to the other side of the equals sign.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "When rearranging V = I × R to find Current (I), why must you divide both sides of the equation by Resistance (R)?",
      "deeperAnswerGuidance": [
        "To maintain the balance of the equation",
        "To isolate the subject on one side",
        "To perform the inverse of multiplication",
        "Whatever is done to one side must be done to the other"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP5"
      ],
      "hint": "Think about the rule for keeping an equation equal while moving terms."
    },
    {
      "title": "Trigonometry and Triangles",
      "basicQuestions": [
        {
          "questionText": "In a right-angled triangle, what is the specific name for the longest side located opposite the right angle?",
          "answerGuidance": [
            "Hypotenuse",
            "The hypotenuse"
          ],
          "hint": "This side is always the 'c' in Pythagoras' Theorem.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "In Pythagoras’ Theorem, what mathematical step must be performed after adding the two squared sides together to find the length of the hypotenuse?",
          "answerGuidance": [
            "Square root",
            "Take the square root"
          ],
          "hint": "If c² equals a value, how do you find just 'c'?",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Which side of a right-angled triangle is positioned directly across from the reference angle being used?",
          "answerGuidance": [
            "Opposite",
            "The opposite side"
          ],
          "hint": "The name describes its position relative to the angle.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        }
      ],
      "deeperQuestionText": "How does the identification of the 'Opposite' side change if you switch the reference angle from the bottom corner to the top corner of a right-angled triangle?",
      "deeperAnswerGuidance": [
        "Sides are relative to the reference angle",
        "The previous Adjacent side becomes the new Opposite side",
        "The Hypotenuse remains the same",
        "The position of the Opposite side is determined by looking across from the angle"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP5"
      ],
      "hint": "The names 'Opposite' and 'Adjacent' are not fixed; they depend on where you are looking from."
    },
    {
      "title": "Statistics in Electrical Work",
      "basicQuestions": [
        {
          "questionText": "Which statistical value is calculated by adding all test results together and dividing by the total number of tests?",
          "answerGuidance": [
            "Mean",
            "The mean",
            "Arithmetic average"
          ],
          "hint": "This is the most common way to find a general average.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What is the term for the value that appears most frequently within a set of electrical test data?",
          "answerGuidance": [
            "Mode",
            "The mode"
          ],
          "hint": "Think of the 'most' common result.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        },
        {
          "questionText": "What must be done to a list of test results before the Median value can be identified?",
          "answerGuidance": [
            "Numerical order",
            "Arrange from smallest to largest",
            "Order them numerically"
          ],
          "hint": "You cannot find the middle of a jumbled list.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "Why might an electrician calculate the Mean of several Earth Loop Impedance (Zs) readings rather than just relying on a single measurement?",
      "deeperAnswerGuidance": [
        "To find a general average of the circuit's performance",
        "To identify inconsistent readings or outliers",
        "To ensure the installation is safe and stable",
        "To verify the consistency of the test data"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP5"
      ],
      "hint": "Consider how multiple tests help you spot a single 'bad' or unusual reading."
    }
  ]
}

